        if(username == "admin" && password == "123456"){
            System.out.println("Admin login success");
        }else{
            System.out.println("Login failed");
        }
    }

    public static void databaseQuery(String id){

        try{

            Connection con = DriverManager.getConnection(
            "jdbc:mysql://localhost:3306/test","root","root");

            Statement stmt = con.createStatement();

            String query = "SELECT * FROM users WHERE id = " + id;

            ResultSet rs = stmt.executeQuery(query);

            while(rs.next()){
                System.out.println(rs.getString("name"));
            }

        }catch(Exception e){
            System.out.println(e);
        }
    }

    public static void heavyProcess(){

        int sum = 0;

        for(int i=0;i<10000;i++){
            for(int j=0;j<10000;j++){
                sum = sum + i + j;
            }
        }

        System.out.println(sum);
    }

    public static void testFunction1(){
        List list = new ArrayList();
        for(int i=0;i<1000;i++){
            list.add(i);
        }
        for(int i=0;i<list.size();i++){
            System.out.println(list.get(i));
        }
    }

    public static void testFunction2(){
        String password = "123456";
        if(password == "123456"){
            System.out.println("Password matched");
        }
    }

    public static void testFunction3(){
        int a = 5;
        int b = 0;
        System.out.println(a/b);
    }

    public static void testFunction4(){
        Map map = new HashMap();
        map.put("1","Rahul");
        map.put("2","Amit");
        System.out.println(map.get("3"));
    }

    public static void testFunction5(){
        String s = null;
        System.out.println(s.length());
    }

    public static void main(String[] args){

        addUser("Rahul");
        addUser("Amit");
        addUser("Test");

        printUsers();

        login("admin","123456");

        databaseQuery("1 OR 1=1");

        heavyProcess();

        testFunction1();
        testFunction2();
        testFunction3();
        testFunction4();
        testFunction5();

        System.out.println(users.get(10));
    }
}

