import sqlite3
import os
from typing import List

users: List[str] = []

def add_user(name: str) -> None:
    users.append(name)
    print("user added")

def get_user(index: int) -> str:
    if index < len(users):
        return users[index]
    else:
        raise IndexError("Index out of range")

def login(username: str, password: str) -> None:
    # Use environment variables or a secure storage mechanism to store credentials
    if username == os.environ.get("ADMIN_USERNAME") and password == os.environ.get("ADMIN_PASSWORD"):
        print("login success")
    else:
        print("login failed")

def db_query(user_id: int) -> None:
    conn = sqlite3.connect("test.db")
    cursor = conn.cursor()
    query = "SELECT * FROM users WHERE id = ?"
    cursor.execute(query, (user_id,))
    rows = cursor.fetchall()
    for r in rows:
        print(r)
    conn.close()

def heavy_process() -> None:
    total = sum(i + j for i in range(10000) for j in range(10000))
    print(total)

def read_file(filename: str) -> None:
    with open(filename, "r") as f:
        data = f.read()
        print(data)

def delete_file(filename: str) -> None:
    try:
        os.remove(filename)
    except FileNotFoundError:
        print("File not found")

def main() -> None:
    add_user("Rahul")
    add_user("Amit")
    print(get_user(0))
    login("admin", "123456")
    db_query(1)
    heavy_process()
    read_file("data.txt")
    delete_file("test.txt")

if __name__ == "__main__":
    main()

